class Solution:
    def occurrencesOfElement(self, nums, queries, x):
        positions = [i for i, v in enumerate(nums) if v == x]
        result = []
        for q in queries:
            result.append(positions[q - 1] if q - 1 < len(positions) else -1)
        return result

